import { forwardRef, useImperativeHandle, useCallback, useRef } from "react";
import type { AnimatedIconHandle, AnimatedIconProps } from "./types";
import { motion, useAnimate } from "motion/react";

const SmartphoneIcon = forwardRef<AnimatedIconHandle, AnimatedIconProps>(
  (
    { size = 24, color = "currentColor", strokeWidth = 2, className = "" },
    ref,
  ) => {
    const [scope, animate] = useAnimate();
    const animationControls = useRef<Array<ReturnType<typeof animate>>>([]);

    const start = useCallback(() => {
      animationControls.current.forEach((control) => control.stop());
      animationControls.current = [];

      animationControls.current.push(
        animate(
          ".phone-body",
          {
            x: [0, -1, 1, -1, 1, 0],
            rotate: [0, -1.5, 1.5, -1.5, 1.5, 0],
          },
          { duration: 0.35, ease: "easeInOut", repeat: Infinity },
        ),
      );

      animationControls.current.push(
        animate(
          ".screen",
          { opacity: [1, 0.35, 1] },
          { duration: 0.7, ease: "easeInOut", repeat: Infinity },
        ),
      );

      animationControls.current.push(
        animate(
          ".home-button",
          { scale: [1, 1.5, 1] },
          { duration: 0.5, ease: "easeInOut", repeat: Infinity },
        ),
      );
    }, [animate]);

    const stop = useCallback(() => {
      animationControls.current.forEach((control) => control.stop());
      animationControls.current = [];

      animate(
        ".phone-body, .screen, .home-button",
        { x: 0, rotate: 0, opacity: 1, scale: 1 },
        { duration: 0.2, ease: "easeOut" },
      );
    }, [animate]);

    useImperativeHandle(ref, () => ({
      startAnimation: start,
      stopAnimation: stop,
    }));

    return (
      <motion.svg
        ref={scope}
        xmlns="http://www.w3.org/2000/svg"
        width={size}
        height={size}
        viewBox="0 0 24 24"
        fill="none"
        stroke={color}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeLinejoin="round"
        className={`cursor-pointer ${className}`}
        onHoverStart={start}
        onHoverEnd={stop}
      >
        <path stroke="none" d="M0 0h24v24H0z" fill="none" />

        <motion.g
          className="phone-body"
          style={{ transformOrigin: "12px 12px" }}
        >
          <path d="M6 5a2 2 0 0 1 2 -2h8a2 2 0 0 1 2 2v14a2 2 0 0 1 -2 2h-8a2 2 0 0 1 -2 -2v-14z" />
          <motion.path
            className="screen"
            d="M8 6h8a1 1 0 0 1 1 1v9a1 1 0 0 1 -1 1H8a1 1 0 0 1 -1 -1V7a1 1 0 0 1 1 -1z"
          />
        </motion.g>

        <motion.circle
          className="home-button"
          cx="12"
          cy="17"
          r="1"
          fill={color}
          stroke="none"
          style={{ transformOrigin: "12px 17px" }}
        />
      </motion.svg>
    );
  },
);

SmartphoneIcon.displayName = "SmartphoneIcon";
export default SmartphoneIcon;

import type { SVGProps } from "react";

export type IconEasing =
  | "linear"
  | "easeIn"
  | "easeOut"
  | "easeInOut"
  | "circIn"
  | "circOut"
  | "circInOut"
  | "backIn"
  | "backOut"
  | "backInOut"
  | "anticipate";

export interface AnimatedIconProps extends Omit<
  SVGProps<SVGSVGElement>,
  | "ref"
  | "onAnimationStart"
  | "onAnimationEnd"
  | "onAnimationIteration"
  | "onDrag"
  | "onDragEnd"
  | "onDragEnter"
  | "onDragExit"
  | "onDragLeave"
  | "onDragOver"
  | "onDragStart"
  | "onDrop"
  | "values"
> {
  /** Icon size in pixels or CSS string */
  size?: number | string;
  /** Icon color (defaults to currentColor) */
  color?: string;
  /** SVG stroke width */
  strokeWidth?: number;
  /** Additional CSS classes */
  className?: string;
}

export interface AnimatedIconHandle {
  startAnimation: () => void;
  stopAnimation: () => void;
}
